import json
import pickle
import os
import boto3
from botocore.exceptions import ClientError

def lambda_handler(event, context):
    # Validate the incoming event
    if 'body' not in event:
        return {
            'statusCode': 400,
            'body': json.dumps('Invalid request')
        }
    
    try:
        # Deserialize the JSON payload
        payload = json.loads(event['body'])
        
        # Validate the payload structure
        if not validate_payload(payload):
            return {
                'statusCode': 400,
                'body': json.dumps('Invalid payload structure')
            }
        
        # Process the payload (example processing)
        processed_data = process_payload(payload)
        
        # Serialize the processed data using pickle
        serialized_data = pickle.dumps(processed_data)
        
        # Store serialized data securely (example using S3)
        s3_client = boto3.client('s3')
        bucket_name = os.environ['S3_BUCKET']
        object_key = f"processed_data/{context.aws_request_id}.pkl"
        
        s3_client.put_object(Bucket=bucket_name, Key=object_key, Body=serialized_data)
        
        return {
            'statusCode': 200,
            'body': json.dumps('Event processed successfully')
        }
    
    except json.JSONDecodeError:
        return {
            'statusCode': 400,
            'body': json.dumps('Invalid JSON format')
        }
    except ClientError as e:
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error storing data: {str(e)}')
        }

def validate_payload(payload):
    # Implement validation logic for the payload structure
    required_keys = ['user_id', 'action', 'timestamp']
    return all(key in payload for key in required_keys)

def process_payload(payload):
    # Implement your processing logic here
    return {
        'user_id': payload['user_id'],
        'action': payload['action'],
        'timestamp': payload['timestamp'],
        'status': 'processed'
    }